#include<stdio.h>
#include<string.h>
char v[1001][10];int n=0;
int mirror(int l,int r){
  if(l>=n||r>=n)return 1;
  if(strcmp(v[l],"N")==0&&strcmp(v[r],"N")==0)return 1;
  if(strcmp(v[l],"N")==0||strcmp(v[r],"N")==0)return 0;
  if(strcmp(v[l],v[r])!=0)return 0;
  return mirror(2*l+1,2*r+2)&&mirror(2*l+2,2*r+1);
}
int main(){while(scanf("%s",v[n])==1)n++;puts(mirror(1,2)?"YES":"NO");}
